import*as Browser from"@hyperjump/browser";import*as Instance from"../../annotations/annotated-instance.js";import{pointerSegments}from"@hyperjump/json-pointer";const id="https://json-schema.org/keyword/unknown",compile=e=>{return[[...pointerSegments(e.cursor)].pop(),Browser.value(e)]},interpret=([e,r],t,n,o,p,i)=>{e=id+"#"+e;return Instance.setAnnotation(t,e,i,r),!0};export default{id:id,compile:compile,interpret:interpret};